/// The full case fold of `c`, or `None` when `c` folds to its plain lowercase.
pub fn casefold_override(c: char) -> Option<&'static str> {
    let cp = c as u32;
    CASEFOLD_OVERRIDES
        .binary_search_by(|&(k, _)| k.cmp(&cp))
        .ok()
        .map(|i| CASEFOLD_OVERRIDES[i].1)
}
